const VERIFY_TOKEN = '123456';
const input = $input.first().json;

// Handle Meta webhook verification (GET request)
const query = input.query || {};
if (query['hub.mode']) {
  if (query['hub.mode'] === 'subscribe' && query['hub.verify_token'] === VERIFY_TOKEN) {
    return [{ json: { type: 'verification', skip: true } }];
  }
  return [{ json: { type: 'forbidden', skip: true } }];
}

// Parse incoming WhatsApp message (POST request)
const body = input.body || input;
const entry = body.entry?.[0];
const change = entry?.changes?.[0];
const value = change?.value;
const message = value?.messages?.[0];
const contact = value?.contacts?.[0];

if (!message) return [{ json: { type: 'no_message', skip: true } }];

const msgAge = Math.floor(Date.now() / 1000) - parseInt(message.timestamp || 0);
if (msgAge > 300) return [{ json: { type: 'expired', skip: true } }];

// Handle audio/voice messages
if (message.type === 'audio') {
  return [{
    json: {
      skip: false,
      messageId: message.id,
      from: message.from,
      type: 'audio',
      audioId: message.audio.id,
      text: '',
      name: contact?.profile?.name || '',
      timestamp: message.timestamp,
      phoneNumberId: value.metadata?.phone_number_id
    }
  }];
}

if (message.type !== 'text' && message.type !== 'interactive') return [{ json: { type: message.type, skip: true } }];

const text = (message.text?.body || message.interactive?.button_reply?.title || '').trim();
if (!text) return [{ json: { type: 'empty_text', skip: true } }];

return [{
  json: {
    skip: false,
    messageId: message.id,
    from: message.from,
    type: message.type,
    text,
    name: contact?.profile?.name || '',
    timestamp: message.timestamp,
    phoneNumberId: value.metadata?.phone_number_id
  }
}];

const data = $('Prepare Data').item.json;
const convRaw = $('Get Conversation').item.json.value;
const custRaw = $('Get Customer Data').item.json.value;

// For voice messages, use transcribed text from Inject Transcription
let text = data.text;
try {
  const inj = $('Inject Transcription').item.json;
  if (inj && inj.isVoiceMessage) text = inj.text;
} catch(e) {}

let conversation = [];
try { conversation = JSON.parse(convRaw || '[]'); } catch(e) {}

let customer = {};
try { customer = JSON.parse(custRaw || '{}'); } catch(e) {}

return [{
  json: {
    from: data.from,
    text,
    name: data.name || customer.name || '',
    phoneNumberId: data.phoneNumberId,
    sessionKey: data.sessionKey,
    customerKey: data.customerKey,
    conversation,
    customer,
    pendingBooking: customer.pendingBooking || null
  }
}];

const ctx = $input.first().json;

// Hard-code slot selection - handles typed (1/2/3), time strings, am/pm, ordinals EN+ID
if (ctx.pendingBooking && ctx.pendingBooking.step === 'awaiting_slot_selection') {
  const slots = ctx.pendingBooking.slots || [];
  const txt = ctx.text.trim().toLowerCase();
  let slotIndex = -1;

  // Numeric: 1, 2, 3
  const num = parseInt(txt);
  if (num >= 1 && num <= slots.length) slotIndex = num - 1;

  // Number > 3: treat as time hour (e.g. "9" = 09:00, "10" = 10:00)
  if (slotIndex < 0 && !isNaN(num) && num >= 1 && num <= 23) {
    const hh = String(num).padStart(2, '0');
    slotIndex = slots.findIndex(s => s.time === hh + ':00');
    if (slotIndex < 0) slotIndex = slots.findIndex(s => s.time === hh + ':30');
  }

  // Time with colon or dot: 09:00, 9:00, 9.30
  if (slotIndex < 0) {
    const tm = txt.match(/(d{1,2})[.:](d{2})/);
    if (tm) {
      const timeStr = tm[1].padStart(2, '0') + ':' + tm[2];
      slotIndex = slots.findIndex(s => s.time === timeStr);
    }
  }

  // Time with am/pm: 9am, 9 am, 10am
  if (slotIndex < 0) {
    const ampm = txt.match(/(\d{1,2})(?::(\d{2}))?\s*am/);
    if (ampm) {
      const timeStr = ampm[1].padStart(2, '0') + ':' + (ampm[2] || '00');
      slotIndex = slots.findIndex(s => s.time === timeStr);
    }
  }

  // Spoken time — full EN + ID lookup table
  if (slotIndex < 0) {
    const hourMap = {
      // English
      'one': '01', 'two': '02', 'three': '03', 'four': '04',
      'five': '05', 'six': '06', 'seven': '07', 'eight': '08',
      'nine': '09', 'ten': '10', 'eleven': '11', 'twelve': '12',
      // Indonesian
      'satu': '01', 'dua': '02', 'tiga': '03', 'empat': '04',
      'lima': '05', 'enam': '06', 'tujuh': '07', 'delapan': '08',
      'sembilan': '09', 'sepuluh': '10', 'sebelas': '11', 'dua belas': '12'
    };
    const minuteMap = {
      'thirty': '30', 'half': '30', 'tiga puluh': '30',
      'fifteen': '15', 'quarter': '15', 'lima belas': '15',
      'forty five': '45', 'empat puluh lima': '45'
    };
    // setengah X = half past (X-1) in Indonesian: "setengah sepuluh" = 09:30
    const setengahMap = {
      'dua': '01', 'tiga': '02', 'empat': '03', 'lima': '04',
      'enam': '05', 'tujuh': '06', 'delapan': '07', 'sembilan': '08',
      'sepuluh': '09', 'sebelas': '10', 'dua belas': '11'
    };
    // Check "setengah X" first (Indonesian half-past)
    const setengahMatch = txt.match(/setengah\s+(\w+(?:\s+\w+)?)/);
    if (setengahMatch) {
      const nextWord = setengahMatch[1];
      if (setengahMap[nextWord]) slotIndex = slots.findIndex(s => s.time === setengahMap[nextWord] + ':30');
    }
    // Check hour word + optional minute word
    if (slotIndex < 0) {
      let hour = null, minute = '00';
      // Try two-word hours first (dua belas, etc.)
      for (const [word, h] of Object.entries(hourMap)) {
        if (txt.includes(word)) { hour = h; break; }
      }
      if (hour) {
        for (const [word, m] of Object.entries(minuteMap)) {
          if (txt.includes(word)) { minute = m; break; }
        }
        slotIndex = slots.findIndex(s => s.time === hour + ':' + minute);
      }
    }
  }

    // Ordinals — English + Indonesian
  if (slotIndex < 0) {
    const ordMap = [
      ['first','one','satu','pertama','1st'],
      ['second','two','dua','kedua','2nd','nomor 2','no 2','number 2'],
      ['third','three','tiga','ketiga','3rd','nomor 3','no 3','number 3']
    ];
    for (let i = 0; i < ordMap.length; i++) {
      if (i < slots.length && ordMap[i].some(k => txt.includes(k))) { slotIndex = i; break; }
    }
  }

  if (slotIndex >= 0) {
    return [{ json: Object.assign({}, ctx, { _slotIndex: slotIndex, ollamaBody: null }) }];
  }
}

// Hard-code cancel confirmation reply - don't send to LLM, avoids "yes" being misclassified as intent=cancel again
if (ctx.pendingBooking && ctx.pendingBooking.step === 'awaiting_cancel_confirmation') {
  return [{ json: Object.assign({}, ctx, { _cancelConfirm: true, ollamaBody: null }) }];
}

// Time reselect bypass — user providing new time after "X not available"
if (ctx.pendingBooking && ctx.pendingBooking.step === 'awaiting_time_reselect') {
  const txt = ctx.text.trim().toLowerCase();
  let time = null;
  const ampm = txt.match(/(\d{1,2})(?::(\d{2}))?\s*(am|pm)/i);
  const colon = txt.match(/(\d{1,2})[.:](\d{2})/);
  const bare = txt.match(/^(\d{1,2})$/);
  if (ampm) {
    let h = parseInt(ampm[1]); const min = ampm[2] || '00';
    if (ampm[3].toLowerCase() === 'pm' && h < 12) h += 12;
    if (ampm[3].toLowerCase() === 'am' && h === 12) h = 0;
    time = String(h).padStart(2,'0') + ':' + min;
  } else if (colon) { time = colon[1].padStart(2,'0') + ':' + colon[2]; }
  else if (bare) { time = bare[1].padStart(2,'0') + ':00'; }
  if (time) {
    return [{ json: Object.assign({}, ctx, { _newTime: time, ollamaBody: null }) }];
  }
}


const todayDate = new Date();
const today = todayDate.toISOString().slice(0, 10);
const dayNames = ['Sunday','Monday','Tuesday','Wednesday','Thursday','Friday','Saturday'];
const todayFull = dayNames[todayDate.getDay()] + ', ' + today;

// Pre-compute next 7 days with explicit day-name → date mapping (so LLM doesn't need to calculate)
const dateMap = [];
for (let i = 1; i <= 7; i++) {
  const d = new Date(todayDate);
  d.setDate(todayDate.getDate() + i);
  const iso = d.toISOString().slice(0, 10);
  const label = i === 1 ? 'Tomorrow' : dayNames[d.getDay()];
  dateMap.push('- ' + label + ': ' + iso);
}
const upcomingDays = dateMap.join('\n');

const systemPrompt = "You are an appointment booking assistant for Bright Smile Dental Clinic.\n" +
  "Today is " + todayFull + ".\n" +
      "Upcoming dates:\n" + upcomingDays + "\n\n" +
  "Services available:\n" +
  "- Cleaning (30 minutes)\n" +
  "- First Visit (60 minutes)\n" +
  "- Emergency (30 minutes)\n\n" +
  "Business hours: Monday-Sunday, open 24 hours\n\n" +
  "Current pending booking context: " + JSON.stringify(ctx.pendingBooking || null) + "\n" +
  "Recent conversation (last 6 messages): " + JSON.stringify(ctx.conversation.slice(-6)) + "\n\n" +
  "Analyze the user message and respond ONLY with valid JSON:\n" +
  "{\n" +
  "  \"intent\": \"booking\" | \"reschedule\" | \"cancel\" | \"confirmation\" | \"unclear\",\n" +
  "  \"service\": \"Cleaning\" | \"First Visit\" | \"Emergency\" | null,\n" +
  "  \"date\": \"YYYY-MM-DD\" | null,\n" +
  "  \"time\": \"HH:MM\" | null,\n" +
  "  \"name\": null,\n" +
  "  \"notes\": null,\n" +
  "  \"confidence\": 0.0,\n" +
  "  \"reply\": \"\"\n" +
  "}\n\n" +
  "Rules:\n" +
  "- Always resolve relative dates (next Monday, tomorrow, today, for the day, tonight) using today: " + todayFull + "\n" +
  "- Use list_appointments intent when user asks about their existing appointments — e.g. 'what is my appointment', 'my appointment', 'show my bookings', 'do I have appointments', 'what time is my appointment', 'check my schedule'\n" +
  "- Write reply in friendly conversational tone\n" +
  "- When user says thanks/ok/bye after a completed booking, reply with a short warm closing only — do NOT prompt to book/reschedule/cancel";

const requestBody = {
  model: 'llama3:latest',
  messages: [
    { role: 'system', content: systemPrompt },
    { role: 'user', content: ctx.text }
  ],
  format: 'json',
  stream: false
};

return [{ json: Object.assign({}, ctx, { ollamaBody: JSON.stringify(requestBody) }) }];

const ctx = $('Build Ollama Request').item.json;

// Slot selection bypass - _slotIndex set by Build Ollama Request, skip LLM response
if (ctx._slotIndex !== undefined && ctx._slotIndex !== null) {
  const slot = (ctx.pendingBooking && ctx.pendingBooking.slots ? ctx.pendingBooking.slots[ctx._slotIndex] : null);
  return [{
    json: {
      from: ctx.from, text: ctx.text, name: ctx.name,
      phoneNumberId: ctx.phoneNumberId, sessionKey: ctx.sessionKey,
      customerKey: ctx.customerKey, conversation: ctx.conversation,
      customer: ctx.customer, pendingBooking: ctx.pendingBooking,
      intent: 'confirmation',
      extracted: {
        service: ctx.pendingBooking ? ctx.pendingBooking.service : null,
        date: ctx.pendingBooking ? ctx.pendingBooking.date : null,
        time: slot ? slot.time : null,
        name: ctx.name || null,
        notes: null
      },
      selectedSlot: slot || null,
      confidence: 1.0,
      aiReply: ''
    }
  }];
}

// Cancel confirmation bypass - _cancelConfirm set by Build Ollama Request, skip LLM response
// Handle Confirmation node already inspects ctx.text for yes/no during awaiting_cancel_confirmation,
// so forcing intent to 'confirmation' here is enough to stop the LLM from re-classifying "yes" as intent=cancel
if (ctx._cancelConfirm) {
  return [{
    json: {
      from: ctx.from, text: ctx.text, name: ctx.name,
      phoneNumberId: ctx.phoneNumberId, sessionKey: ctx.sessionKey,
      customerKey: ctx.customerKey, conversation: ctx.conversation,
      customer: ctx.customer, pendingBooking: ctx.pendingBooking,
      intent: 'confirmation',
      extracted: {
        service: null, date: null, time: null,
        name: ctx.name || null, notes: null
      },
      confidence: 1.0,
      aiReply: ''
    }
  }];
}

// Time reselect bypass — _newTime set by Build Ollama Request
if (ctx._newTime) {
  return [{
    json: {
      from: ctx.from, text: ctx.text, name: ctx.name,
      phoneNumberId: ctx.phoneNumberId, sessionKey: ctx.sessionKey,
      customerKey: ctx.customerKey, conversation: ctx.conversation,
      customer: ctx.customer, pendingBooking: ctx.pendingBooking,
      intent: 'booking',
      extracted: {
        service: ctx.pendingBooking ? ctx.pendingBooking.service : null,
        date: ctx.pendingBooking ? ctx.pendingBooking.date : null,
        time: ctx._newTime,
        name: ctx.name || null, notes: null
      },
      confidence: 1.0, aiReply: ''
    }
  }];
}


// Reschedule date bypass — _rescheduleDate set by Build Ollama Request
if (ctx._rescheduleDate) {
  return [{
    json: {
      from: ctx.from, text: ctx.text, name: ctx.name,
      phoneNumberId: ctx.phoneNumberId, sessionKey: ctx.sessionKey,
      customerKey: ctx.customerKey, conversation: ctx.conversation,
      customer: ctx.customer, pendingBooking: ctx.pendingBooking,
      intent: 'booking',
      extracted: {
        service: ctx.pendingBooking ? ctx.pendingBooking.service : null,
        date: ctx._rescheduleDate,
        time: ctx._rescheduleTime || null,
        name: ctx.name || null,
        notes: null
      },
      confidence: 1.0,
      aiReply: ''
    }
  }];
}


const aiResponse = $input.first().json;
let parsed = {};
try {
  const content = aiResponse.message && aiResponse.message.content ? aiResponse.message.content : (aiResponse.response || '');
  parsed = JSON.parse(content);
} catch(e) {
  parsed = { intent: 'unclear', confidence: 0, reply: 'Sorry, I had trouble understanding. Could you please rephrase?' };
}

// Reschedule date intercept - user just provided new date for reschedule
if (ctx.pendingBooking && ctx.pendingBooking.step === 'awaiting_reschedule_date') {
  const date = parsed.date || null;
  if (date) {
    return [{
      json: {
        from: ctx.from, text: ctx.text, name: ctx.name,
        phoneNumberId: ctx.phoneNumberId, sessionKey: ctx.sessionKey,
        customerKey: ctx.customerKey, conversation: ctx.conversation,
        customer: ctx.customer, pendingBooking: ctx.pendingBooking,
        intent: 'booking',
        extracted: {
          service: ctx.pendingBooking.service,
          date: date,
          time: parsed.time || null,
          name: parsed.name || ctx.name || null,
          notes: null
        },
        confidence: 1.0,
        aiReply: ''
      }
    }];
  }
}

return [{
  json: {
    from: ctx.from, text: ctx.text, name: ctx.name,
    phoneNumberId: ctx.phoneNumberId, sessionKey: ctx.sessionKey,
    customerKey: ctx.customerKey, conversation: ctx.conversation,
    customer: ctx.customer, pendingBooking: ctx.pendingBooking,
    intent: parsed.intent || 'unclear',
    extracted: {
      service: parsed.service || null,
      date: parsed.date || null,
      time: parsed.time || null,
      name: parsed.name || ctx.name || null,
      notes: parsed.notes || null
    },
    confidence: parsed.confidence || 0,
    aiReply: parsed.reply || ''
  }
}];

const ctx = $('Parse Intent Response').item.json;
const result = $input.first().json;
const slots = result.slots || [];

if (!ctx.extracted.date) {
  return [{
    json: {
      ...ctx,
      autoBooked: false,
      responseText: 'What date would you like to book? (e.g. Monday, tomorrow, July 14)',
      pendingBooking: { ...ctx.pendingBooking, service: ctx.extracted.service, step: 'awaiting_date' }
    }
  }];
}

if (!ctx.extracted.service) {
  return [{
    json: {
      ...ctx,
      autoBooked: false,
      responseText: 'Which service do you need?\n\n1. Cleaning (30 min)\n2. First Visit (60 min)\n3. Emergency (30 min)',
      pendingBooking: { step: 'awaiting_service', date: ctx.extracted.date }
    }
  }];
}

if (slots.length === 0) {
  return [{
    json: {
      ...ctx,
      autoBooked: false,
      responseText: 'Sorry, no available slots on ' + ctx.extracted.date + '. Would you like to try a different date?',
      pendingBooking: null
    }
  }];
}

const topSlots = slots.slice(0, 3);
const isReschedule = ctx.pendingBooking && ctx.pendingBooking.existingAppointmentId;
const extracted = ctx.extracted;

// ── preferred time matching (only for fresh bookings, not reschedule) ──────────
const preferredTime = ctx.extracted.time || null;
let matchedSlot = null;

if (preferredTime) {
  let normalizedTime = null;

  // "9am", "10am", "9:00am"
  const ampmMatch = preferredTime.match(/(\d{1,2})(?::(\d{2}))?\s*am/i);
  // "09:00", "9:00", "9.30"
  const colonMatch = preferredTime.match(/(\d{1,2})[.:](\d{2})/);
  // bare hour: "9", "10"
  const hourMatch = preferredTime.match(/^(\d{1,2})$/);

  if (ampmMatch) {
    normalizedTime = ampmMatch[1].padStart(2, '0') + ':' + (ampmMatch[2] || '00');
  } else if (colonMatch) {
    normalizedTime = colonMatch[1].padStart(2, '0') + ':' + colonMatch[2];
  } else if (hourMatch) {
    normalizedTime = hourMatch[1].padStart(2, '0') + ':00';
  }

  if (normalizedTime) {
    matchedSlot = slots.find(s => s.time === normalizedTime) || null;
  }
}

if (matchedSlot) {
  return [{
    json: {
      ...ctx,
      autoBooked: true,
      selectedSlot: matchedSlot,
      extracted: { ...ctx.extracted, time: matchedSlot.time },
      pendingBooking: isReschedule ? {
        existingAppointmentId: ctx.pendingBooking.existingAppointmentId,
        existingCalendarEventId: ctx.pendingBooking.existingCalendarEventId,
        service: ctx.pendingBooking.service,
        name: ctx.pendingBooking.name,
        isReschedule: true
      } : null
    }
  }];
}

// ── build response message ────────────────────────────────────────────────────
const newPendingBooking = {
  service: extracted.service,
  date: extracted.date,
  name: extracted.name || ctx.name,
  phone: ctx.from,
  slots: topSlots,
  step: 'awaiting_slot_selection'
};
let msg = '';
if (preferredTime) {
  msg = 'Sorry, *' + preferredTime + '* is not available on ' + extracted.date + '. Please provide a different time.';
  newPendingBooking.step = 'awaiting_time_reselect';
} else {
  msg += 'Available slots for *' + extracted.service + '* on *' + extracted.date + '*:\n\n';
  topSlots.forEach(function(slot, i) { msg += (i + 1) + '. ' + slot.time + '\n'; });
  msg += '\nReply with *1*, *2*, or *3* to confirm your appointment.';
}

if (isReschedule) {
  newPendingBooking.existingAppointmentId = ctx.pendingBooking.existingAppointmentId;
  newPendingBooking.existingCalendarEventId = ctx.pendingBooking.existingCalendarEventId;
  newPendingBooking.isReschedule = true;
}

return [{
  json: {
    ...ctx,
    autoBooked: false,
    responseText: msg,
    pendingBooking: newPendingBooking
  }
}];

const ctx = $('Parse Intent Response').item.json;
const appt = $input.first().json;

if (!appt || !appt.id) {
  return [{ json: { ...ctx, responseText: "I couldn't find an active appointment. Would you like to book a new one?", pendingBooking: null } }];
}

// Get time from LLM extraction OR parse from raw text
let extractedTime = (ctx.extracted && ctx.extracted.time && ctx.extracted.time !== 'null') ? ctx.extracted.time : null;
if (!extractedTime) {
  const txt = ctx.text.trim().toLowerCase();
  const ampm = txt.match(/(\d{1,2})(?::(\d{2}))?\s*(am|pm)/i);
  const colon = txt.match(/(\d{1,2})[.:](\d{2})/);
  if (ampm) {
    let h = parseInt(ampm[1]); const min = ampm[2] || '00';
    if (ampm[3].toLowerCase() === 'pm' && h < 12) h += 12;
    if (ampm[3].toLowerCase() === 'am' && h === 12) h = 0;
    extractedTime = String(h).padStart(2,'0') + ':' + min;
  } else if (colon) {
    extractedTime = colon[1].padStart(2,'0') + ':' + colon[2];
  }
}

const extractedDate = (ctx.extracted && ctx.extracted.date && ctx.extracted.date !== 'null') ? ctx.extracted.date : null;

const pendingBooking = {
  step: 'awaiting_reschedule_date',
  existingAppointmentId: appt.id,
  existingCalendarEventId: appt.calendarEventId,
  service: appt.service,
  name: appt.name,
  phone: ctx.from,
  date: appt.date,
  time: extractedTime || null
};

let responseText;
if (extractedTime && !extractedDate) {
  responseText = 'Found your appointment:\n\n*' + appt.service + '*\n' + appt.date + ' at ' + appt.time + '\n\nI will reschedule to *' + extractedTime + '*. Reply *today* to confirm same date, or provide a different date.';
} else {
  responseText = 'Found your appointment:\n\n*' + appt.service + '*\n' + appt.date + ' at ' + appt.time + '\n\nWhat date would you like to reschedule to?';
}

return [{ json: { ...ctx, responseText, pendingBooking } }];

const ctx = $('Parse Intent Response').item.json;
const appt = $input.first().json;

if (!appt || !appt.id) {
  return [{
    json: {
      ...ctx,
      responseText: "I couldn't find an active appointment for your number.",
      pendingBooking: null
    }
  }];
}

return [{
  json: {
    ...ctx,
    responseText: `Are you sure you want to cancel your appointment?\n\n?? *${appt.service}*\n?? ${appt.date} at ${appt.time}\n\nReply *YES* to confirm cancellation.`,
    pendingBooking: {
      step: 'awaiting_cancel_confirmation',
      existingAppointmentId: appt.id,
      existingCalendarEventId: appt.calendarEventId,
      service: appt.service,
      date: appt.date,
      time: appt.time
    }
  }
}];

const ctx = $('Parse Intent Response').item.json;
const pending = ctx.pendingBooking;
const text = ctx.text.trim().toLowerCase();

if (!pending || !pending.step) {
  return [{ json: { ...ctx, confirmAction: 'none', responseText: ctx.aiReply || 'How can I help you? You can book, reschedule, or cancel an appointment.' } }];
}

if (pending.step === 'awaiting_slot_selection') {
  // If Parse Intent Response bypass already resolved the slot, use it directly
  if (ctx.selectedSlot) {
    const confirmAction = pending.isReschedule ? 'reschedule_event' : 'create_event';
    return [{ json: { ...ctx, confirmAction, selectedSlot: ctx.selectedSlot, pending } }];
  }

  const slots = pending.slots || [];
  let slot = null;

  // Numeric: 1, 2, 3
  const choice = parseInt(text) - 1;
  if (choice >= 0 && choice < slots.length) slot = slots[choice];

  // Number as hour: "9" = 09:00
  if (!slot && !isNaN(parseInt(text))) {
    const hh = String(parseInt(text)).padStart(2, '0');
    slot = slots.find(s => s.time === hh + ':00') || slots.find(s => s.time === hh + ':30') || null;
  }

  // Time with colon or dot: 09:00, 9:00, 9.30
  if (!slot) {
    const tm = text.match(/(\d{1,2})[.:]( \d{2})/);
    if (tm) slot = slots.find(s => s.time === tm[1].padStart(2,'0') + ':' + tm[2].trim()) || null;
  }

  // Time with am/pm: 9am, 9 am, 10am
  if (!slot) {
