const ctx = $('Parse Intent Response').item.json;
const pending = ctx.pendingBooking;
const text = ctx.text.trim().toLowerCase();

if (!pending || !pending.step) {
  return [{ json: { ...ctx, confirmAction: 'none', responseText: ctx.aiReply || 'How can I help you? You can book, reschedule, or cancel an appointment.' } }];
}

if (pending.step === 'awaiting_slot_selection') {
  // If Parse Intent Response bypass already resolved the slot, use it directly
  if (ctx.selectedSlot) {
    const confirmAction = pending.isReschedule ? 'reschedule_event' : 'create_event';
    return [{ json: { ...ctx, confirmAction, selectedSlot: ctx.selectedSlot, pending } }];
  }

  const slots = pending.slots || [];
  let slot = null;

  // Numeric: 1, 2, 3
  const choice = parseInt(text) - 1;
  if (choice >= 0 && choice < slots.length) slot = slots[choice];

  // Number as hour: "9" = 09:00
  if (!slot && !isNaN(parseInt(text))) {
    const hh = String(parseInt(text)).padStart(2, '0');
    slot = slots.find(s => s.time === hh + ':00') || slots.find(s => s.time === hh + ':30') || null;
  }

  // Time with colon or dot: 09:00, 9:00, 9.30
  if (!slot) {
    const tm = text.match(/(\d{1,2})[.:]( \d{2})/);
    if (tm) slot = slots.find(s => s.time === tm[1].padStart(2,'0') + ':' + tm[2].trim()) || null;
  }

  // Time with am/pm: 9am, 9 am, 10am
  if (!slot) {
    const ampm = text.match(/(\d{1,2})(?::(\d{2}))?\s*am/);
    if (ampm) slot = slots.find(s => s.time === ampm[1].padStart(2,'0') + ':' + (ampm[2] || '00')) || null;
  }

  // Spoken hour words EN + ID
  if (!slot) {
    const hourMap = {
      'one':'01','two':'02','three':'03','four':'04','five':'05','six':'06',
      'seven':'07','eight':'08','nine':'09','ten':'10','eleven':'11','twelve':'12',
      'satu':'01','dua':'02','tiga':'03','empat':'04','lima':'05','enam':'06',
      'tujuh':'07','delapan':'08','sembilan':'09','sepuluh':'10','sebelas':'11'
    };
    const minuteMap = { 'thirty':'30','half':'30','tiga puluh':'30' };
    let hour = null, minute = '00';
    for (const [w, h] of Object.entries(hourMap)) { if (text.includes(w)) { hour = h; break; } }
    if (hour) {
      for (const [w, m] of Object.entries(minuteMap)) { if (text.includes(w)) { minute = m; break; } }
      slot = slots.find(s => s.time === hour + ':' + minute) || null;
    }
  }

  // Ordinals EN + ID
  if (!slot) {
    const ordMap = [
      ['first','one','satu','pertama','1st'],
      ['second','dua','kedua','2nd','nomor 2','no 2','number 2'],
      ['third','tiga','ketiga','3rd','nomor 3','no 3','number 3']
    ];
    for (let i = 0; i < ordMap.length; i++) {
      if (i < slots.length && ordMap[i].some(k => text.includes(k))) { slot = slots[i]; break; }
    }
  }

  if (!slot) {
    return [{ json: { ...ctx, confirmAction: 'none', responseText: 'Please reply with *1*, *2*, or *3* to select your preferred time slot.' } }];
  }
  const confirmAction = pending.isReschedule ? 'reschedule_event' : 'create_event';
  return [{ json: { ...ctx, confirmAction, selectedSlot: slot, pending } }];
}

if (pending.step === 'awaiting_cancel_confirmation') {
  if (text === 'yes' || text === 'ya' || text === 'yeah' || text === 'yep' || text === 'ok' || text === 'okay') {
    return [{ json: { ...ctx, confirmAction: 'cancel_event', pending } }];
  }
  return [{ json: { ...ctx, confirmAction: 'none', responseText: 'Cancellation aborted. Your appointment is still active.' } }];
}

return [{ json: { ...ctx, confirmAction: 'none', responseText: ctx.aiReply || 'How can I help you?' } }];

